mapper.select:
SELECT c.*, u.username, u.nickname, u.avatar
FROM t_comment c LEFT JOIN t_user u ON c.user_id = u.user_id
WHERE c.comment_id = #{commentId}

SELECT c.*, u.username, u.nickname, u.avatar FROM t_comment c LEFT JOIN t_user u ON c.user_id = u.user_id
AND c.content LIKE CONCAT('%',#{keyword},'%')
ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}
